		for(int n = 0; 10 > n; n++)
		{
			RSComplex t3 = {neg_1n[n], 0.0};
			RSComplex top = c_sub(c_mul(t3, fast_cexp(c_mul(t1, Z))), one);
			RSComplex t4 = {denominator_left[n], 0.0};
			RSComplex t5 = {144.0, 0.0};
			RSComplex bot = c_sub(t4, c_mul(t5, c_mul(Z, Z)));
			RSComplex t6 = {an[n], 0.0};
			sum = c_add(sum, c_mul(t6, c_div(top, bot)));
		}
		W = c_add(W, c_mul(prefactor, c_mul(Z, sum)));
		return W;
	}
	else
	{
		RSComplex a = {0.512424224754768462984202823134979415014943561548661637413182, 0.0};
		RSComplex b = {0.275255128608410950901357962647054304017026259671664935783653, 0.0};
		RSComplex c = {0.051765358792987823963876628425793170829107067780337219430904, 0.0};
		RSComplex d = {2.724744871391589049098642037352945695982973740328335064216346, 0.0};

		RSComplex ii = {0.0, 1.0};
		RSComplex Z2 = c_mul(Z, Z);
		return c_mul(c_mul(Z, ii), c_add(c_div(a, c_sub(Z2, b)), c_div(c, c_sub(Z2, d))));
	}
}

static inline void calculate_micro_xs(
	double * micro_xs, int nuc, double E, Input input,
	__global int * n_windows, __global double * pseudo_K0RS,
	__global Window * windows, __global Pole * poles,
	int max_num_windows, int max_num_poles)
{
	double sigT, sigA, sigF, sigE;

	double spacing = 1.0 / (double)n_windows[nuc];
	int window = (int)(E / spacing);
	if(n_windows[nuc] == window)
		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	for(int i = w.start; w.end > i; i++)
	{
		RSComplex t1 = {0.0, 1.0};
		RSComplex t2 = {sqrt(E), 0.0};
		Pole pole = poles[nuc * max_num_poles + i];
		RSComplex PSIIKI = c_div(t1, c_sub(pole.MP_EA, t2));
		RSComplex E_c = {E, 0.0};
		RSComplex CDUM = c_div(PSIIKI, E_c);
		sigT = sigT + c_mul(pole.MP_RT, c_mul(CDUM, sigTfactors[pole.l_value])).r;
		sigA = sigA + c_mul(pole.MP_RA, CDUM).r;
		sigF = sigF + c_mul(pole.MP_RF, CDUM).r;
	}

	sigE = sigT - sigA;
	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

static inline void calculate_micro_xs_doppler(
	double * micro_xs, int nuc, double E, Input input,
	__global int * n_windows, __global double * pseudo_K0RS,
	__global Window * windows, __global Pole * poles,
	int max_num_windows, int max_num_poles)
{
	double sigT, sigA, sigF, sigE;

	double spacing = 1.0 / (double)n_windows[nuc];
	int window = (int)(E / spacing);
	if(n_windows[nuc] == window)
		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	double dopp = 0.5;

	for(int i = w.start; w.end > i; i++)
	{
		Pole pole = poles[nuc * max_num_poles + i];
		RSComplex E_c = {E, 0.0};
		RSComplex dopp_c = {dopp, 0.0};
		RSComplex Z = c_mul(c_sub(E_c, pole.MP_EA), dopp_c);

		RSComplex faddeeva = fast_nuclear_W(Z);

		sigT = sigT + c_mul(pole.MP_RT, c_mul(faddeeva, sigTfactors[pole.l_value])).r;
		sigA = sigA + c_mul(pole.MP_RA, faddeeva).r;
		sigF = sigF + c_mul(pole.MP_RF, faddeeva).r;
	}

	sigE = sigT - sigA;
	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

static inline void calculate_macro_xs(
	double * macro_xs, int mat, double E, Input input,
	__global int * num_nucs, __global int * mats, int max_num_nucs,
	__global double * concs, __global int * n_windows, __global double * pseudo_K0RS,
	__global Window * windows, __global Pole * poles,
	int max_num_windows, int max_num_poles)
{
	for(int i = 0; 4 > i; i++)
		macro_xs[i] = 0.0;

	for(int i = 0; num_nucs[mat] > i; i++)
	{
		double micro_xs[4];
		int nuc = mats[mat * max_num_nucs + i];

		if(1 == input.doppler)
			calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
		else
			calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

		for(int j = 0; 4 > j; j++)
			macro_xs[j] += micro_xs[j] * concs[mat * max_num_nucs + i];
	}
}

__kernel void macro_xs_lookup_kernel(
	Input in,
	__global int * num_nucs,
	__global int * mats,
	int max_num_nucs,
	__global double * concs,
	__global int * n_windows,
	__global double * pseudo_K0RS,
	__global Window * windows,
	__global Pole * poles,
	int max_num_windows,
	int max_num_poles,
	__global int * verification)
{
	int i = get_global_id(0);
	if(in.lookups <= i)
		return;

	ulong seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, (ulong)(2 * i));

	double E = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	double macro_xs[4] = {0.0, 0.0, 0.0, 0.0};
	calculate_macro_xs(macro_xs, mat, E, in, num_nucs, mats, max_num_nucs, concs, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

	double max = -1.7976931348623157e+308;
	int max_idx = 0;
	for(int x = 0; 4 > x; x++)
	{
		if(max < macro_xs[x])
		{
			max = macro_xs[x];
			max_idx = x;
		}
	}
	verification[i] = max_idx + 1;
}

