inline double LCG_random_double(ulong *seed)
{
	const ulong m = 9223372036854775808UL;
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = 9223372036854775808UL;
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n % m;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while (n > 0UL)
	{
		if (n & 1UL)
		{
			a_new = a_new * a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a = a * a;
		n >>= 1;
	}

	return (a_new * seed + c_new) % m;
}

inline int pick_mat(ulong *seed)
{
	double dist[12];
	dist[0]  = 0.140;
	dist[1]  = 0.052;
	dist[2]  = 0.275;
	dist[3]  = 0.134;
	dist[4]  = 0.154;
	dist[5]  = 0.064;
	dist[6]  = 0.066;
	dist[7]  = 0.055;
	dist[8]  = 0.008;
	dist[9]  = 0.015;
	dist[10] = 0.025;
	dist[11] = 0.013;

	double roll = LCG_random_double(seed);

	for (int i = 0; i < 12; i++)
	{
		double running = 0.0;
		for (int j = i; j > 0; j--)
			running += dist[j];
